<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\SoftDeletes;
class BillingDocument extends Model{use SoftDeletes;protected $fillable=['document_number','document_type','status','order_id','customer_id','order_price_quote_id','currency','subtotal_amount','tax_amount','total_amount','issued_at','due_at','paid_at','voided_at','metadata','created_by_id','updated_by_id'];protected function casts():array{return ['subtotal_amount'=>'decimal:2','tax_amount'=>'decimal:2','total_amount'=>'decimal:2','issued_at'=>'datetime','due_at'=>'datetime','paid_at'=>'datetime','voided_at'=>'datetime','metadata'=>'array'];}public function order(){return $this->belongsTo(Order::class);}public function customer(){return $this->belongsTo(User::class,'customer_id');}public function quote(){return $this->belongsTo(OrderPriceQuote::class,'order_price_quote_id');}public function paymentRecords(){return $this->hasMany(PaymentRecord::class);}public function events(){return $this->hasMany(BillingDocumentEvent::class)->orderByDesc('created_at');}}
